// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { getOverview, getUsers, getRiders, getApprovedCaptains, getPendingCaptains } from "../../services/adminApi";
//import { useAuth } from "../../contexts/AuthContext";

import { Button } from "@mui/material";

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [overview, setOverview] = useState({});
  const [data, setData] = useState([]);
  const [activeTab, setActiveTab] = useState("overview");

  useEffect(() => {
    fetchOverview();
  }, []);

  const fetchOverview = async () => {
    const res = await getOverview();
    setOverview(res.data);
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    let res;
    if (type === "users") res = await getUsers();
    if (type === "riders") res = await getRiders();
    if (type === "captains") res = await getApprovedCaptains();
    if (type === "pending") res = await getPendingCaptains();
    setData(res?.data[type === "users" ? "users" : type === "riders" ? "riders" : type === "captains" ? "captains" : "pendingCaptains"] || []);
  };

  return (
    <div>
      <Button variant="contained" color="error" onClick={logout}>Logout</Button>

      <h1>Admin Dashboard</h1>
      <div>
        <button onClick={() => fetchData("users")}>Users ({overview.users || 0})</button>
        <button onClick={() => fetchData("riders")}>Riders ({overview.riders || 0})</button>
        <button onClick={() => fetchData("captains")}>Approved Captains ({overview.captains || 0})</button>
        <button onClick={() => fetchData("pending")}>Pending Captains ({overview.pendingCaptains || 0})</button>
        <button onClick={() => fetchData("rides")}>Rides ({overview.rides || 0})</button>
      </div>

      <table>
        <thead>
          <tr>
            <th>Name</th><th>Email</th><th>Mobile</th><th>Role</th><th>Approval Status</th>
          </tr>
        </thead>
        <tbody>
          {data.length === 0 && <tr><td colSpan="5">No data found</td></tr>}
          {data.map((item) => (
            <tr key={item._id}>
              <td>{item.fullName}</td>
              <td>{item.email}</td>
              <td>{item.mobile}</td>
              <td>{item.role}</td>
              <td>{item.approvalStatus || "-"}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
